class Solution:
    def maxProduct(self, nums):
        best = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                best = max(best, (nums[i] - 1) * (nums[j] - 1))
        return best

solutions.python:
class Solution:
    def maxProduct(self, nums):
        nums.sort(reverse=True)
        return (nums[0] - 1) * (nums[1] - 1)

